const response = $input.first().json;

const messageOutput = response.output.find(item => item.type === 'message');
const textContent = messageOutput.content[0].text;
const parsed = typeof textContent === 'string' ? JSON.parse(textContent) : textContent;

const blocks = [];

if (parsed.stories && parsed.stories.length > 0) {
  blocks.push({
    type: 'heading_1',
    heading_1: { rich_text: [{ type: 'text', text: { content: 'Stories' } }] }
  });

  for (const story of parsed.stories) {
    blocks.push({
      type: 'heading_2',
      heading_2: { rich_text: [{ type: 'text', text: { content: story.headline } }] }
    });

    blocks.push({
      type: 'paragraph',
      paragraph: { rich_text: [{ type: 'text', text: { content: story.summary } }] }
    });

    const analysis = [
      `Cross-Outlet Comparison: ${story.crossOutletComparison}`,
      `Critical Analysis: ${story.criticalAnalysis}`,
      `Technical Reality Check: ${story.technicalRealityCheck}`,
      `Strategic Significance: ${story.strategicSignificance}`,
      `Confidence: ${story.confidenceAssessment}`
    ].join('\n\n');

    // Notion API has a 2000 char limit per rich_text block — chunk if needed
    const chunks = analysis.match(/.{1,2000}/gs) || [];
    for (const chunk of chunks) {
      blocks.push({
        type: 'paragraph',
        paragraph: { rich_text: [{ type: 'text', text: { content: chunk } }] }
      });
    }
  }
}

blocks.push({
  type: 'heading_1',
  heading_1: { rich_text: [{ type: 'text', text: { content: 'Analysis Summary' } }] }
});

const summaryFields = [
  `Most Overhyped Story: ${parsed.mostOverhypedStory}`,
  `Most Underreported Story: ${parsed.mostUnderreportedStory}`,
  `Corporate Framing vs Technical Reality: ${parsed.corporateFramingVsTechnicalReality}`,
  `What the Industry Wants Readers to Believe: ${parsed.whatTheIndustryWantsReadersTobelieve}`
];

for (const field of summaryFields) {
  const chunks = field.match(/.{1,2000}/gs) || [];
  for (const chunk of chunks) {
    blocks.push({
      type: 'paragraph',
      paragraph: { rich_text: [{ type: 'text', text: { content: chunk } }] }
    });
  }
}

// Extract all citations from the parsed stories
const citations = [];

for (const story of parsed.stories) {
  const fields = [
    story.summary,
    story.crossOutletComparison,
    story.criticalAnalysis,
    story.technicalRealityCheck,
    story.strategicSignificance,
    story.confidenceAssessment
  ];

  for (const field of fields) {
    const matches = [...field.matchAll(/\[([^\]]+)\]\((https?:\/\/[^\)]+)\)/g)];
    for (const match of matches) {
      citations.push({
        headline: story.headline,
        linkText: match[1],
        url: match[2]
      });
    }
  }
}

// Deduplicate citations by URL
const seen = new Set();
const uniqueCitations = citations.filter(c => {
  if (seen.has(c.url)) return false;
  seen.add(c.url);
  return true;
});

return [{ json: { blocks, citations: uniqueCitations } }];
